#include <bits/stdc++.h>
using namespace std;
long long dp[102][102][102];
bool use[102][102][102];
int n,k,a[102][102];
void dfs(int x,int y,int rest){
	if(use[x][y][rest] || x>n)
		return;
	if(rest==0)
		dfs(x+1,y,rest),dfs(x+1,y+1,rest),dp[x][y][rest]=a[x][y]+max(dp[x+1][y][rest],dp[x+1][y+1][rest]);
	else if(n-x==rest-1)
		dfs(x+1,y,rest-1),dfs(x+1,y+1,rest-1),dp[x][y][rest]=1LL*a[x][y]*3+max(dp[x+1][y][rest-1],dp[x+1][y+1][rest-1]);
    else{
		dfs(x+1,y,rest),dfs(x+1,y+1,rest);
		dfs(x+1,y,rest-1),dfs(x+1,y+1,rest-1);
		dp[x][y][rest]=a[x][y]+max(dp[x+1][y][rest],dp[x+1][y+1][rest]);
		dp[x][y][rest]=max(dp[x][y][rest],1LL*a[x][y]*3+max(dp[x+1][y][rest-1],dp[x+1][y+1][rest-1]));
	}
	use[x][y][rest]=1;
}
int main(){
	scanf("%d%d",&n,&k);
	for(int i=1;i<=n;i++)
		for(int j=1;j<=i;j++)
			scanf("%d",&a[i][j]);
	k=min(k,n);
	for(int i=0;i<=k;i++)
		dfs(1,1,i);
	long long ans=-1e18;
	for(int i=0;i<=k;i++)
		ans=max(ans,dp[1][1][i]);
	printf("%lld",ans);
	return 0;
}
